import { HTTP_INTERCEPTORS, HttpClient } from '@angular/common/http';
import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
import { TestBed } from '@angular/core/testing';
import { JwtInterceptor } from './jwt.interceptor';
import { LoadingService } from '../services/loading.service';
import { environment } from '../../../environments/environment';

const STORAGE_KEY = 'trmdict_token';

describe('JwtInterceptor', () => {
    let http: HttpClient;
    let httpMock: HttpTestingController;
    let loading: LoadingService;

    beforeEach(() => {
        localStorage.removeItem(STORAGE_KEY);
        TestBed.configureTestingModule({
            imports: [HttpClientTestingModule],
            providers: [{ provide: HTTP_INTERCEPTORS, useClass: JwtInterceptor, multi: true }],
        });
        http = TestBed.inject(HttpClient);
        httpMock = TestBed.inject(HttpTestingController);
        loading = TestBed.inject(LoadingService);
    });

    afterEach(() => {
        httpMock.verify();
        localStorage.removeItem(STORAGE_KEY);
    });

    it('should attach Authorization header when token is present and URL matches apiBaseUrl', () => {
        localStorage.setItem(STORAGE_KEY, 'jwt-xyz');
        http.get(`${environment.apiBaseUrl}/v1/foo`).subscribe();
        const req = httpMock.expectOne(`${environment.apiBaseUrl}/v1/foo`);
        expect(req.request.headers.get('Authorization')).toBe('Bearer jwt-xyz');
        req.flush({});
    });

    it('should NOT attach Authorization for external URLs', () => {
        localStorage.setItem(STORAGE_KEY, 'jwt-xyz');
        http.get('https://external.example.com/data').subscribe();
        const req = httpMock.expectOne('https://external.example.com/data');
        expect(req.request.headers.has('Authorization')).toBe(false);
        req.flush({});
    });

    it('should NOT attach Authorization when token is absent', () => {
        http.get(`${environment.apiBaseUrl}/v1/public`).subscribe();
        const req = httpMock.expectOne(`${environment.apiBaseUrl}/v1/public`);
        expect(req.request.headers.has('Authorization')).toBe(false);
        req.flush({});
    });

    it('should call LoadingService.start before request and stop after response', (done) => {
        const startSpy = spyOn(loading, 'start').and.callThrough();
        const stopSpy = spyOn(loading, 'stop').and.callThrough();
        http.get(`${environment.apiBaseUrl}/v1/x`).subscribe({
            complete: () => {
                expect(startSpy).toHaveBeenCalledTimes(1);
                expect(stopSpy).toHaveBeenCalledTimes(1);
                done();
            },
        });
        const req = httpMock.expectOne(`${environment.apiBaseUrl}/v1/x`);
        req.flush({});
    });
});
